<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  body{font-family:Arial,sans-serif;margin:0;padding:20px;background:#f4f5f7;}
  .board{display:flex;gap:15px;}
  .column{background:white;border-radius:6px;flex:1;display:flex;flex-direction:column;height:80vh;}
  .header{padding:10px;font-weight:bold;border-bottom:1px solid #ddd;background:#fafafa;position:relative;}
  .count{font-size:.9em;color:#555;margin-left:8px;}
  .card-container{flex:1;padding:10px;overflow-y:auto;}
  .card{background:#fff;border-radius:4px;padding:10px;margin-bottom:8px;box-shadow:0 1px 3px rgba(0,0,0,.1);display:flex;justify-content:space-between;align-items:center;}
  .card-del{background:none;border:none;color:#c00;font-weight:bold;cursor:pointer;}
  #new-card{width:calc(100% - 80px);padding:8px;margin-right:5px;}
  #add-card{padding:8px 12px;}
</style>
</head>
<body>

<h1>Kanban Board</h1>

<div style="margin-bottom:15px;">
  <input type="text" id="new-card" placeholder="New task...">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div id="col-todo" class="column" ondragover="allowDrop(event)" ondrop="dropCard(event)">
    <div class="header">To Do<span class="count"></span></div>
    <div class="card-container"></div>
  </div>
  <div id="col-doing" class="column" ondragover="allowDrop(event)" ondrop="dropCard(event)">
    <div class="header">Doing<span class="count"></span></div>
    <div class="card-container"></div>
  </div>
  <div id="col-done" class="column" ondragover="allowDrop(event)" ondrop="dropCard(event)">
    <div class="header">Done<span class="count"></span></div>
    <div class="card-container"></div>
  </div>
</div>

<script>
const STORAGE_KEY = 'kanbanBoardState';

function loadState() {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : { todo: [], doing: [], done: [] };
}

function saveState(state) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
}

function updateCounts() {
  ['todo', 'doing', 'done'].forEach(col => {
    const countEl = document.querySelector(`#col-${col} .count`);
    const container = document.querySelector(`#col-${col} .card-container`);
    countEl.textContent = `(${container.children.length})`;
  });
}

function createCardElement(title, id) {
  const card = document.createElement('div');
  card.className = 'card';
  card.draggable = true;
  card.dataset.id = id;

  const span = document.createElement('span');
  span.textContent = title;
  card.appendChild(span);

  const delBtn = document.createElement('button');
  delBtn.className = 'card-del';
  delBtn.innerHTML = '&times;';
  delBtn.onclick = () => deleteCard(id);
  card.appendChild(delBtn);

  card.ondragstart = (e) => {
    e.dataTransfer.setData('text/plain', id);
  };

  return card;
}

function renderBoard() {
  const state = loadState();
  ['todo', 'doing', 'done'].forEach(col => {
    const container = document.querySelector(`#col-${col} .card-container`);
    container.innerHTML = '';
    state[col].forEach(cardData => {
      container.appendChild(createCardElement(cardData.title, cardData.id));
    });
  });
  updateCounts();
}

function addNewCard() {
  const input = document.getElementById('new-card');
  const title = input.value.trim();
  if (!title) return;
  const state = loadState();
  const id = Date.now().toString();
  state.todo.push({ id, title });
  saveState(state);
  renderBoard();
  input.value = '';
}

function deleteCard(id) {
  const state = loadState();
  ['todo', 'doing', 'done'].forEach(col => {
    state[col] = state[col].filter(card => card.id !== id);
  });
  saveState(state);
  renderBoard();
}

function allowDrop(ev) { ev.preventDefault(); }

function dropCard(ev) {
  ev.preventDefault();
  const id = ev.dataTransfer.getData('text/plain');
  const targetColEl = ev.currentTarget;
  const colId = targetColEl.id.split('-')[1]; // todo, doing, done
  const state = loadState();

  let cardData = null;
  ['todo', 'doing', 'done'].forEach(col => {
    const idx = state[col].findIndex(c => c.id === id);
    if (idx !== -1) {
      cardData = state[col][idx];
      state[col].splice(idx, 1);
    }
  });

  if (cardData && colId) {
    state[colId].push(cardData);
    saveState(state);
    renderBoard();
  }
}

document.getElementById('add-card').onclick = addNewCard;
document.getElementById('new-card').addEventListener('keypress', e => {
  if (e.key === 'Enter') addNewCard();
});

renderBoard();
</script>
</body>
</html>
